         ["Профилактика", "Курс «Кибергигиена для МСП» с сертификацией", "II квартал 2026 г.", "ОЭБиПК + банки-партнёры", "Повышение зрелости персонала"],
         ["Аналитика", "Обезличенные тематические обзоры по типовым схемам", "Раз в квартал", "Аналитическая служба ОЭБиПК", "Обновление внутренних регламентов предприятий"],
         ["Цифровой мониторинг", "Система «пять индикаторов раннего реагирования»", "Постоянно", "Аналитическая служба ОЭБиПК", "Раннее выявление подозрительных операций"],
         ["Межведомственный обмен", "Рабочая группа «бизнес — ЭБиПК — ФНС — Банк России — Росфинмониторинг»", "Ежеквартально", "УВД по ЮЗАО", "Целостная картина рисков, синхронизация мер"],
